import{_ as s,o as t,c as n,a2 as a}from"./chunks/framework.D2pTuMig.js";const c=JSON.parse('{"title":"Facturation & Paiements","description":"","frontmatter":{"title":"Facturation & Paiements"},"headers":[],"relativePath":"docs/fr/faq/billing.md","filePath":"docs/fr/faq/billing.md"}'),r={name:"docs/fr/faq/billing.md"};function i(o,e,l,u,d,p){return t(),n("div",null,[...e[0]||(e[0]=[a('<h1 id="facturation-paiements" tabindex="-1">Facturation &amp; Paiements <a class="header-anchor" href="#facturation-paiements" aria-label="Permalink to &quot;Facturation &amp; Paiements&quot;">​</a></h1><h2 id="je-ne-vois-pas-mes-revenus-dans-mon-wallet" tabindex="-1">Je ne vois pas mes revenus dans mon Wallet <a class="header-anchor" href="#je-ne-vois-pas-mes-revenus-dans-mon-wallet" aria-label="Permalink to &quot;Je ne vois pas mes revenus dans mon Wallet&quot;">​</a></h2><p>Le crédit n&#39;est pas automatique à la signature, mais à la <strong>réalisation</strong>. Vous devez valider manuellement selon le format :</p><ul><li><strong>Insertion Colis :</strong> Avez-vous rempli votre déclaration de volume hebdomadaire ? (Le lundi ou mardi)</li><li><strong>Email :</strong> Avez-vous cliqué sur <strong>&quot;Valider la diffusion&quot;</strong> après l&#39;envoi ?</li></ul><p>Sans cette action, les fonds restent séquestrés.</p><h2 id="comment-retirer-mes-gains-et-editer-ma-facture" tabindex="-1">Comment retirer mes gains et éditer ma facture ? <a class="header-anchor" href="#comment-retirer-mes-gains-et-editer-ma-facture" aria-label="Permalink to &quot;Comment retirer mes gains et éditer ma facture ?&quot;">​</a></h2><p>Allez dans <strong>Transaction → Exchange</strong> et cliquez sur <code>Retirer</code>. Saisissez le montant.</p><p><strong>Important :</strong> Si des frais de gestion s&#39;appliquent, éditez votre facture en conséquence du montant net reçu.</p><h2 id="a-partir-de-quand-les-revenus-sont-ils-disponibles" tabindex="-1">À partir de quand les revenus sont-ils disponibles ? <a class="header-anchor" href="#a-partir-de-quand-les-revenus-sont-ils-disponibles" aria-label="Permalink to &quot;À partir de quand les revenus sont-ils disponibles ?&quot;">​</a></h2><p>Le revenu de la campagne est versé au solde de votre compte <strong>30 jours après le dernier reporting</strong>. Choisissez ensuite <code>Transférer vers le wallet</code> ou <code>Retirer</code> vos revenus.</p><h2 id="quand-sont-emis-les-paiements" tabindex="-1">Quand sont émis les paiements ? <a class="header-anchor" href="#quand-sont-emis-les-paiements" aria-label="Permalink to &quot;Quand sont émis les paiements ?&quot;">​</a></h2><p>Les paiements sont émis à <strong>30 jours fin de mois</strong>, date de réception de la demande de retrait, à condition que la facture soumise soit valide.</p><h2 id="puis-je-reinvestir-mes-gains" tabindex="-1">Puis-je réinvestir mes gains ? <a class="header-anchor" href="#puis-je-reinvestir-mes-gains" aria-label="Permalink to &quot;Puis-je réinvestir mes gains ?&quot;">​</a></h2><p>Oui, sans frais. Dans <strong>Exchange</strong>, cliquez sur <code>Transférer vers le wallet</code>. Vous pourrez utiliser ce solde immédiatement pour acheter du trafic pour votre propre site.</p><h2 id="pourquoi-mes-revenus-sont-ils-bloques-30-jours" tabindex="-1">Pourquoi mes revenus sont-ils bloqués 30 jours ? <a class="header-anchor" href="#pourquoi-mes-revenus-sont-ils-bloques-30-jours" aria-label="Permalink to &quot;Pourquoi mes revenus sont-ils bloqués 30 jours ?&quot;">​</a></h2><p>Le délai de 30 jours est un <strong>délai de protection</strong> qui sécurise votre paiement et celui de l&#39;annonceur.</p><p>Il permet de détecter et traiter les anomalies éventuelles (cartons perdus, volumes non conformes, campagne interrompue) <strong>avant</strong> que les fonds soient définitivement libérés. Sans ce tampon, getinside ne pourrait pas garantir votre paiement en cas d&#39;impayé annonceur.</p><h2 id="que-se-passe-t-il-si-une-anomalie-est-detectee-pendant-les-30-jours" tabindex="-1">Que se passe-t-il si une anomalie est détectée pendant les 30 jours ? <a class="header-anchor" href="#que-se-passe-t-il-si-une-anomalie-est-detectee-pendant-les-30-jours" aria-label="Permalink to &quot;Que se passe-t-il si une anomalie est détectée pendant les 30 jours ?&quot;">​</a></h2><p>getinside vous contacte directement pour résoudre l&#39;incident. Pendant la résolution, le délai de disponibilité des fonds est suspendu. Une fois l&#39;anomalie traitée, le compteur reprend.</p><p>Dans les cas courants (écart de volume, flyer non conforme), la résolution prend 48 à 72h. Contactez <a href="mailto:support@getinside.fr" target="_blank" rel="noreferrer">support@getinside.fr</a> si vous n&#39;avez pas de retour sous 5 jours ouvrés.</p><h2 id="mes-fonds-peuvent-ils-expirer" tabindex="-1">Mes fonds peuvent-ils expirer ? <a class="header-anchor" href="#mes-fonds-peuvent-ils-expirer" aria-label="Permalink to &quot;Mes fonds peuvent-ils expirer ?&quot;">​</a></h2><p>Oui. Si vous ne vous connectez pas <strong>et</strong> ne retirez pas vos revenus pendant <strong>12 mois consécutifs</strong>, les fonds disponibles expirent et sont définitivement acquis à getinside.</p><p><strong>Comment éviter cela :</strong> connectez-vous régulièrement, ou activez les notifications de solde dans votre espace compte. Un retrait partiel ou un réinvestissement suffit à réinitialiser le compteur.</p>',23)])])}const v=s(r,[["render",i]]);export{c as __pageData,v as default};
